export const SessionUpdateModal: FC<{
  teamId: string;
  isOpen: boolean;
  setIsOpen: Dispatch<SetStateAction<boolean>>;
  session: Session | null;
  onClose?: Function;
  onFail?: Function;
  onSuccess?: Function;
}> = ({ isOpen, setIsOpen, session, onClose, onFail, onSuccess }) => {
  const { services } = useServicesHook();

  const [players, setPlayers] = useState<Player[]>([]);
  const [error, setError] = useState<ServiceError | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  const [param, setParam] = useState<{
    title: string;
    playerId: string | undefined;
    location: string | null;
    note: string;
  }>({
    title: '',
    playerId: undefined,
    location: '',
    note: '',
  });

  const [locations, setLocations] = useState<string[]>([]);

  const getPlayers = async (teamId: string) => {
    const { players, error } = await services.default.player.getPlayers(
      teamId,
      {
        pageSize: AppConstants.SEARCH_DEFAULT_BIG_VALUE,
      },
    );
    if (error) {
      return;
    }

    setPlayers(players);
  };

  const getLocations = async (teamId: string) => {
    const { locations, error } =
      await services.default.session.getLocations(teamId);

    if (error) {
      return;

